import type { Metadata } from "next"
import { FlightOperations } from "./FlightOperations"

export const metadata: Metadata = {
  title: "運航管理（OCC）／ 機材繰り — 羽田基地 | ぐんじょう 航空",
  description:
    "航空会社の運航管理者（OCC ディスパッチャー）向け管制画面。羽田（HND）基地の本日のフライトを運航ボード（便名・区間・STD/STA・ATD/ATA・状態・使用機材・スポット・遅延/理由）で監視し、機材繰り（ローテーション）タイムラインで各機の便→折返し→整備の連鎖を把握。ダイバート・欠航・遅延の波及・ターンアラウンド不足・機材変更要・整備抵触を重大度順の不正常運航アラートでトリアージし、便・機材の詳細にドリルインする。",
}

export default function FlightOperationsPage() {
  return <FlightOperations />
}

"use client"

import * as React from "react"
import type { ColumnDef } from "@gunjo/ui"
import { DataTable, Badge, Tag, Button } from "@gunjo/ui"
import { FLIGHTS, AIRPORT_JA, DELAY_REASONS, type Flight } from "./data"
import { FLIGHT_STATUS } from "./status"

function StatusBadge({ status }: { status: Flight["status"] }) {
  const s = FLIGHT_STATUS[status]
  const Icon = s.Icon
  return (
    <Badge variant={s.variant} icon={<Icon />}>
      {s.label}
    </Badge>
  )
}

// 区間表示 出発→到着（コード＋日本語）
function Sector({ flight }: { flight: Flight }) {
  return (
    <span className="inline-flex items-center gap-1 font-medium tabular-nums">
      <span title={AIRPORT_JA[flight.dep]}>{flight.dep}</span>
      <span aria-hidden="true" className="text-muted-foreground">
        →
      </span>
      <span title={AIRPORT_JA[flight.arr]}>{flight.arr}</span>
    </span>
  )
}

export function FlightBoard({ onSelectFlight }: { onSelectFlight: (flightId: string) => void }) {
  const columns: ColumnDef<Flight>[] = React.useMemo(
    () => [
      {
        accessorKey: "flightNo",
        header: "便名",
        cell: ({ row }) => <span className="font-semibold tabular-nums">{row.original.flightNo}</span>,
      },
      {
        id: "sector",
        header: "区間",
        cell: ({ row }) => <Sector flight={row.original} />,
      },
      {
        id: "std",
        header: "定刻 STD/STA",
        cell: ({ row }) => (
          <span className="tabular-nums text-muted-foreground">
            {row.original.std} / {row.original.sta}
          </span>
        ),
      },
      {
        id: "actual",
        header: "実績 ATD/ATA",
        cell: ({ row }) => (
          <span className="tabular-nums">
            {row.original.atd ?? "—"} / {row.original.ata ?? "—"}
          </span>
        ),
      },
      {
        accessorKey: "status",
        header: "状態",
        cell: ({ row }) => <StatusBadge status={row.original.status} />,
      },
      {
        accessorKey: "reg",
        header: "機材",
        cell: ({ row }) => (
          <div className="flex flex-col leading-tight">
            <span className="font-medium tabular-nums">{row.original.reg}</span>
            <span className="text-xs text-muted-foreground">{row.original.type}</span>
          </div>
        ),
      },
      {
        accessorKey: "spot",
        header: "Spot",
        cell: ({ row }) => <span className="tabular-nums">{row.original.spot}</span>,
      },
      {
        id: "delay",
        header: "遅延",
        cell: ({ row }) => {
          const d = row.original.delayMin ?? 0
          if (d <= 0) return <span className="text-muted-foreground">—</span>
          const variant = d >= 30 ? "destructive" : "default"
          return (
            <div className="flex items-center gap-1.5">
              <Tag variant={variant} size="sm">
                +{d}分
              </Tag>
              {row.original.reason && row.original.reason !== "" ? (
                <span className="text-xs text-muted-foreground" title={DELAY_REASONS[row.original.reason]}>
                  {row.original.reason}
                </span>
              ) : null}
            </div>
          )
        },
      },
      {
        id: "action",
        header: "",
        cell: ({ row }) => (
          <Button
            variant="ghost"
            size="sm"
            onClick={() => onSelectFlight(row.original.id)}
            aria-label={`${row.original.flightNo} の詳細を開く`}
          >
            詳細
          </Button>
        ),
      },
    ],
    [onSelectFlight]
  )

  // 行のトーン — 不正常運航をハイライト
  const getRowState = (row: Flight) =>
    row.status === "cancelled" || row.status === "diverted"
      ? "irregular"
      : (row.delayMin ?? 0) >= 30
        ? "delayed"
        : undefined

  // モバイル（< md）はスタックカードで表示
  const renderCard = (f: Flight) => (
    <button
      type="button"
      onClick={() => onSelectFlight(f.id)}
      className="flex w-full flex-col gap-2 rounded-lg border border-border bg-card p-3 text-left"
    >
      <div className="flex items-center justify-between gap-2">
        <span className="text-base font-semibold tabular-nums">{f.flightNo}</span>
        <StatusBadge status={f.status} />
      </div>
      <div className="flex items-center justify-between text-sm">
        <Sector flight={f} />
        <span className="tabular-nums text-muted-foreground">
          {f.std}→{f.sta}
        </span>
      </div>
      <div className="flex items-center justify-between text-xs text-muted-foreground">
        <span className="tabular-nums">
          {f.reg}・{f.type}・Spot {f.spot}
        </span>
        {(f.delayMin ?? 0) > 0 ? (
          <Tag variant={(f.delayMin ?? 0) >= 30 ? "destructive" : "default"} size="sm">
            +{f.delayMin}分 {f.reason}
          </Tag>
        ) : null}
      </div>
    </button>
  )

  return (
    <DataTable
      columns={columns}
      data={FLIGHTS}
      filter={{ columnId: "flightNo", placeholder: "便名で絞り込み…" }}
      pageSize={25}
      getRowState={getRowState}
      onRowClick={(row) => onSelectFlight(row.id)}
      renderCard={renderCard}
    />
  )
}

"use client"

import * as React from "react"
import {
  Drawer,
  DrawerContent,
  DrawerHeader,
  DrawerTitle,
  DrawerDescription,
  DrawerFooter,
  DrawerClose,
  Button,
  Badge,
  MetadataList,
  RouteStops,
  Separator,
  type RouteStopItem,
} from "@gunjo/ui"
import { FLIGHTS, ROTATIONS, AIRPORT_JA, DELAY_REASONS, type Flight } from "./data"
import { FLIGHT_STATUS } from "./status"

// 機材のローテーションを RouteStops（順序付きの行路）で表示
function rotationStops(reg: string, currentFlightId: string): RouteStopItem[] {
  const legs = FLIGHTS.filter((f) => f.reg === reg).sort((a, b) => a.std.localeCompare(b.std))
  return legs.map((f): RouteStopItem => {
    let status: RouteStopItem["status"]
    if (f.status === "arrived") status = "completed"
    else if (f.status === "cancelled" || f.status === "diverted") status = "failed"
    else if (f.status === "delayed") status = "delayed"
    else if (f.status === "boarding" || f.status === "departed") status = "current"
    else status = "pending"
    return {
      id: f.id,
      title: `${f.flightNo} ${AIRPORT_JA[f.dep]}→${AIRPORT_JA[f.arr]}`,
      description: f.id === currentFlightId ? "▶ 選択中の便" : `Spot ${f.spot}`,
      status,
      plannedTime: f.std,
      actualTime: f.atd,
      meta: f.type,
    }
  })
}

export function FlightDrawer({
  flightId,
  onOpenChange,
}: {
  flightId: string | null
  onOpenChange: (open: boolean) => void
}) {
  const flight: Flight | undefined = flightId ? FLIGHTS.find((f) => f.id === flightId) : undefined
  const open = Boolean(flight)

  return (
    <Drawer open={open} onOpenChange={onOpenChange} direction="right">
      <DrawerContent side="right" className="w-[28rem] max-w-[calc(100%-1rem)]">
        {flight ? <Body flight={flight} /> : null}
        <DrawerFooter>
          <DrawerClose asChild>
            <Button variant="outline">閉じる</Button>
          </DrawerClose>
        </DrawerFooter>
      </DrawerContent>
    </Drawer>
  )
}

function Body({ flight }: { flight: Flight }) {
  const s = FLIGHT_STATUS[flight.status]
  const Icon = s.Icon
  const rotation = ROTATIONS.find((r) => r.reg === flight.reg)

  return (
    <>
      <DrawerHeader>
        <div className="flex items-center gap-2">
          <DrawerTitle className="tabular-nums">{flight.flightNo}</DrawerTitle>
          <Badge variant={s.variant} icon={<Icon />}>
            {s.label}
          </Badge>
        </div>
        <DrawerDescription className="tabular-nums">
          {AIRPORT_JA[flight.dep]}（{flight.dep}）→ {AIRPORT_JA[flight.arr]}（{flight.arr}） ／ {flight.type}・
          {flight.reg}
        </DrawerDescription>
      </DrawerHeader>

      <div className="flex-1 overflow-y-auto px-4 pb-2">
        <MetadataList
          items={[
            { label: "定刻 STD / STA", value: `${flight.std} / ${flight.sta}` },
            { label: "実績 ATD / ATA", value: `${flight.atd ?? "—"} / ${flight.ata ?? "—"}` },
            {
              label: "遅延",
              value:
                (flight.delayMin ?? 0) > 0 ? (
                  <span className="text-warning-foreground">+{flight.delayMin}分</span>
                ) : (
                  "なし"
                ),
            },
            {
              label: "遅延理由",
              value: flight.reason && flight.reason !== "" ? DELAY_REASONS[flight.reason] : "—",
            },
            { label: "スポット / ゲート", value: flight.spot },
            {
              label: "乗務員",
              value: flight.crew ? `機長 ${flight.crew.capt}・副操縦士 ${flight.crew.fo}・CA ${flight.crew.cabin}名` : "—",
            },
          ]}
        />

        {flight.note ? (
          <p className="mt-3 rounded-md bg-muted px-3 py-2 text-sm text-muted-foreground">{flight.note}</p>
        ) : null}

        <Separator className="my-4" />

        <h3 className="mb-2 text-sm font-semibold text-foreground">
          {flight.reg} 機材ローテーション（本日）
        </h3>
        <RouteStops stops={rotationStops(flight.reg, flight.id)} timeLabels={{ planned: "STD", actual: "ATD" }} />
        {rotation?.status === "irregular" ? (
          <p className="mt-1 text-xs text-destructive">この機材は不正常運航（要対応）です。</p>
        ) : null}
      </div>
    </>
  )
}

"use client"

import * as React from "react"
import { Gantt, type GanttItem, type GanttRow, type GanttItemTone } from "@gunjo/ui"
import { ROTATIONS, OPS_DATE, type SegmentKind, type RotationSegment } from "./data"

// 機材繰り（ローテーション）タイムライン
// @gunjo/ui の Gantt を使用。Gantt は「行×時間軸・レーン詰めバー」。
// 各機（登録記号）= 1 行、各セグメント（便/折返し/整備）= 1 本のバー。
// Gantt は datetime（"YYYY-MM-DDTHH:mm"）を受けるので、当日内の時刻を渡せば
// 1日のローテが横一列の連鎖として描ける。

const SEG_TONE: Record<SegmentKind, GanttItemTone> = {
  leg: "info", // 便（フライトレグ）
  ground: "muted", // 折返し（地上）
  maint: "warning", // 整備
}

function segToItem(seg: RotationSegment): GanttItem {
  // 欠航/ダイバートのレグは destructive で上書き
  const tone: GanttItemTone =
    seg.kind === "leg" && seg.sublabel ? "destructive" : seg.tight ? "destructive" : SEG_TONE[seg.kind]
  return {
    id: seg.id,
    rowId: seg.reg,
    start: `${OPS_DATE}T${seg.start}`,
    end: `${OPS_DATE}T${seg.end}`,
    tone,
    label:
      seg.kind === "ground"
        ? seg.label
        : seg.kind === "maint"
          ? `🔧 ${seg.label}`
          : seg.label,
    ariaLabel: `${seg.label}${seg.sublabel ? `（${seg.sublabel}）` : ""} ${seg.start}〜${seg.end}`,
  }
}

const ROW_STATUS_LABEL: Record<string, string> = {
  normal: "正常",
  watch: "要注視",
  irregular: "不正常",
}

export function RotationTimeline({ onSelectFlight }: { onSelectFlight?: (flightId: string) => void }) {
  const rows: GanttRow[] = ROTATIONS.map((r) => ({
    id: r.reg,
    label: r.reg,
    sublabel: `${r.type}・${ROW_STATUS_LABEL[r.status]}`,
  }))

  const items: GanttItem[] = ROTATIONS.flatMap((r) => r.segments.map(segToItem))

  // 当日 06:00〜22:00 のウィンドウ。Gantt は日単位グリッドなので
  // 時間目盛りを別途ヘッダで補う（後述の制約）。
  const windowStart = `${OPS_DATE}T06:00`
  const windowEnd = `${OPS_DATE}T22:00`

  // 06:00〜22:00 を2時間刻みで補助ラベル化（Gantt が時間目盛りを持たないため自作）
  const hourTicks = React.useMemo(() => {
    const ticks: { h: number; leftPct: number }[] = []
    const startH = 6
    const endH = 22
    for (let h = startH; h <= endH; h += 2) {
      ticks.push({ h, leftPct: ((h - startH) / (endH - startH)) * 100 })
    }
    return ticks
  }, [])

  const handleSelect = (item: GanttItem) => {
    const seg = ROTATIONS.flatMap((r) => r.segments).find((s) => s.id === item.id)
    if (seg?.flightId) onSelectFlight?.(seg.flightId)
  }

  return (
    <div className="flex flex-col gap-2">
      {/* 自作の時刻目盛り（Gantt の日付ヘッダの代替）。ガター幅 120px に合わせる */}
      <div className="hidden md:flex" aria-hidden="true">
        <div className="w-[120px] shrink-0 text-xs text-muted-foreground">時刻</div>
        <div className="relative h-4 flex-1">
          {hourTicks.map((t) => (
            <span
              key={t.h}
              className="absolute -translate-x-1/2 text-[10px] tabular-nums text-muted-foreground"
              style={{ left: `${t.leftPct}%` }}
            >
              {String(t.h).padStart(2, "0")}:00
            </span>
          ))}
        </div>
      </div>

      <Gantt
        label="機材繰り（ローテーション）タイムライン"
        rows={rows}
        items={items}
        startDate={windowStart}
        endDate={windowEnd}
        today={`${OPS_DATE}T13:30`}
        dayWidth={1100}
        laneHeight={30}
        rowLabelWidth={120}
        onSelectItem={handleSelect}
        className="rounded-lg border border-border"
      />

      {/* 凡例 — 色だけに依存しないため文言も併記 */}
      <div className="flex flex-wrap items-center gap-x-4 gap-y-1 px-1 text-xs text-muted-foreground">
        <LegendDot className="bg-info-subtle border-info-border" label="便（フライトレグ）" />
        <LegendDot className="bg-muted border-border" label="折返し（地上）" />
        <LegendDot className="bg-warning-subtle border-warning-border" label="整備" />
        <LegendDot className="bg-destructive-subtle border-destructive-border" label="欠航 / ダイバート / 折返し不足" />
        <span className="ml-auto tabular-nums">縦線＝現在時刻 13:30</span>
      </div>
    </div>
  )
}

function LegendDot({ className, label }: { className: string; label: string }) {
  return (
    <span className="inline-flex items-center gap-1.5">
      <span className={`inline-block h-3 w-3 rounded-sm border ${className}`} aria-hidden="true" />
      {label}
    </span>
  )
}
